#include <iostream>#include <vector>#include <algorithm>#include <climits> using namespace std; int main() {    int n;    cin >> n;    int maxHeight = INT_MIN;    int minHeight = INT_MAX;    int maxIndex = -1;    int minIndex = -1;     for (int i = 0; i < n; ++i) {        int h;        cin >> h;         if (h > maxHeight) {            maxHeight = h;            maxIndex = i;        }         if (h <= minHeight) {            minHeight = h;            minIndex = i;        }    }    int swaps = maxIndex + (n - 1 - minIndex);     if (maxIndex > minIndex) {        swaps -= 1;    }     cout << swaps << endl;     return 0;}